// pages/RestaurantItemsPage.jsx
//
// Route (React Router v6):
//   <Route path="/res/:resId" element={<RestaurantItemsPage />} />
//
// Link examples:
//   /res/123?dish=paneer
//   /res/123?cuisine=indian
//   /res/123?cuisine=chinese&dish=momos

import { useState, useMemo, useEffect } from "react";
import { useParams, useSearchParams, useNavigate } from "react-router-dom";
import { useSelector } from "react-redux";
import { selectEnrichedBindings, selectRestaurantById } from "./redux_utils/foodSlice";

// ── Palette ───────────────────────────────────────────────────────
const CUISINE_PALETTE = {
  chinese:      { grad: "135deg,#FF922B,#E64D00", accent: "#FF922B", glow: "#FF922B40", emoji: "🥡" },
  indian:       { grad: "135deg,#FF6B9D,#FF3D7F", accent: "#FF6B9D", glow: "#FF6B9D40", emoji: "🍛" },
  italian:      { grad: "135deg,#4D96FF,#1565C0", accent: "#4D96FF", glow: "#4D96FF40", emoji: "🍝" },
  soups:        { grad: "135deg,#38D9A9,#00897B", accent: "#38D9A9", glow: "#38D9A940", emoji: "🍲" },
  dessert:      { grad: "135deg,#CC5DE8,#9C27B0", accent: "#CC5DE8", glow: "#CC5DE840", emoji: "🍰" },
  "sweet dish": { grad: "135deg,#FFD93D,#FFC300", accent: "#FFD93D", glow: "#FFD93D40", emoji: "🍭" },
};
const DEFAULT_PALETTE = {
  grad: "135deg,#a78bfa,#7c3aed", accent: "#a78bfa", glow: "#a78bfa40", emoji: "🍽️",
};
const getPalette = (key) => CUISINE_PALETTE[key?.toLowerCase()] ?? DEFAULT_PALETTE;

// ── Dish Item Card ────────────────────────────────────────────────
function DishCard({ dish, accent, glow, idx }) {
  const [hovered, setHovered] = useState(false);
  const [imgLoaded, setImgLoaded] = useState(false);
  const [imgError, setImgError] = useState(false);

  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        background: hovered
          ? `linear-gradient(145deg, ${accent}14, ${accent}08)`
          : "rgba(255,255,255,0.028)",
        border: `1px solid ${hovered ? accent + "50" : "rgba(255,255,255,0.07)"}`,
        borderRadius: 24,
        overflow: "hidden",
        transition: "all 0.3s cubic-bezier(.34,1.56,.64,1)",
        transform: hovered ? "translateY(-6px) scale(1.02)" : "none",
        boxShadow: hovered
          ? `0 20px 60px ${glow}, 0 4px 20px rgba(0,0,0,0.5)`
          : "0 2px 16px rgba(0,0,0,0.3)",
        animation: `dishIn 0.6s cubic-bezier(.34,1.56,.64,1) ${idx * 0.07}s both`,
        cursor: "default",
        display: "flex",
        flexDirection: "column",
      }}
    >
      {/* Image area */}
      <div style={{
        position: "relative",
        height: 200,
        background: `linear-gradient(145deg, ${accent}18, ${accent}08)`,
        overflow: "hidden",
        flexShrink: 0,
      }}>
        {dish.dish_image && !imgError ? (
          <>
            {/* Blur placeholder shown until image loads */}
            {!imgLoaded && (
              <div style={{
                position: "absolute", inset: 0,
                background: `linear-gradient(145deg,${accent}22,${accent}08)`,
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: "3rem",
              }}>
                🍽️
              </div>
            )}
            <img
              src={dish.dish_image_link}
              alt={dish.dish_name}
              onLoad={() => setImgLoaded(true)}
              onError={() => setImgError(true)}
              style={{
                width: "100%", height: "100%", objectFit: "cover",
                opacity: imgLoaded ? 1 : 0,
                transition: "opacity 0.4s ease, transform 0.4s ease",
                transform: hovered ? "scale(1.06)" : "scale(1)",
              }}
            />
          </>
        ) : (
          <div style={{
            width: "100%", height: "100%",
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: "4rem",
          }}>
            🍽️
          </div>
        )}

        {/* Gradient overlay at bottom of image */}
        <div style={{
          position: "absolute", bottom: 0, left: 0, right: 0, height: 80,
          background: "linear-gradient(transparent, rgba(10,8,20,0.85))",
          pointerEvents: "none",
        }} />

        {/* Cuisine badge on image */}
        <div style={{
          position: "absolute", top: 12, left: 12,
          background: `${accent}22`,
          backdropFilter: "blur(10px)",
          border: `1px solid ${accent}55`,
          borderRadius: 10, padding: "3px 10px",
          fontFamily: "'Nunito',sans-serif", fontWeight: 800,
          fontSize: "0.7rem", color: accent,
          textTransform: "capitalize", letterSpacing: "0.04em",
        }}>
          {dish.cuisine}
        </div>

        {/* Keyword tag at bottom-left of image */}
        <div style={{
          position: "absolute", bottom: 10, left: 12,
          fontFamily: "'Nunito',sans-serif", fontWeight: 700,
          fontSize: "0.72rem", color: "rgba(255,255,255,0.5)",
          backdropFilter: "blur(4px)",
        }}>
          #{dish.dishKeyword}
        </div>
      </div>

      {/* Content */}
      <div style={{ padding: "16px 18px 20px", flex: 1 }}>
        <h3 style={{
          margin: "0 0 8px",
          fontFamily: "'Nunito', sans-serif", fontWeight: 900,
          fontSize: "1.05rem", color: "#fff",
          lineHeight: 1.2,
        }}>
          {dish.dish_name}
        </h3>

        {/* Shimmer accent line */}
        <div style={{
          height: 2, width: hovered ? "60%" : "30%",
          background: `linear-gradient(90deg, ${accent}, transparent)`,
          borderRadius: 2, marginBottom: 10,
          transition: "width 0.4s ease",
        }} />
      </div>
    </div>
  );
}

// ── Restaurant Hero ───────────────────────────────────────────────
function RestaurantHero({ restaurant, palette, totalItems }) {
  const [imgLoaded, setImgLoaded] = useState(false);

  if (!restaurant) return null;

  return (
    <div style={{
      position: "relative",
      marginBottom: 0,
      animation: "heroIn 0.7s cubic-bezier(.34,1.56,.64,1) both",
    }}>
      {/* Cover image */}
      <div style={{
        height: "clamp(180px, 28vw, 280px)",
        position: "relative", overflow: "hidden",
        background: `linear-gradient(145deg, ${palette.accent}28, ${palette.accent}08)`,
      }}>
        {restaurant.res_image ? (
          <img
            src={restaurant.res_image}
            alt={restaurant.name}
            onLoad={() => setImgLoaded(true)}
            style={{
              width: "100%", height: "100%", objectFit: "cover",
              opacity: imgLoaded ? 0.6 : 0, transition: "opacity 0.5s ease",
              filter: "saturate(1.1)",
            }}
          />
        ) : null}

        {/* Deep gradient over image */}
        <div style={{
          position: "absolute", inset: 0,
          background: `linear-gradient(to bottom, ${palette.accent}18 0%, rgba(10,8,20,0.92) 100%)`,
        }} />

        {/* Animated background glow */}
        <div style={{
          position: "absolute", inset: 0,
          background: `radial-gradient(ellipse at 30% 50%, ${palette.accent}15, transparent 70%)`,
        }} />

        {/* Hero text on image */}
        <div style={{
          position: "absolute", bottom: 24, left: 24, right: 24,
        }}>
          <div style={{
            display: "flex", alignItems: "flex-end", gap: 16, flexWrap: "wrap",
          }}>
            {/* Restaurant avatar */}
            <div style={{
              width: 72, height: 72, borderRadius: 20, overflow: "hidden", flexShrink: 0,
              border: `3px solid ${palette.accent}`,
              boxShadow: `0 8px 32px ${palette.glow}`,
              background: `${palette.accent}22`,
              display: "flex", alignItems: "center", justifyContent: "center",
              fontSize: "2rem",
            }}>
              {restaurant.res_image
                ? <img src={restaurant.res_image} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                : "🏪"
              }
            </div>

            <div style={{ flex: 1, minWidth: 0 }}>
              <h1 style={{
                margin: "0 0 4px",
                fontFamily: "'Nunito', sans-serif", fontWeight: 900,
                fontSize: "clamp(1.3rem, 4vw, 2rem)", color: "#fff",
                textShadow: "0 2px 20px rgba(0,0,0,0.8)",
                whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
              }}>
                {restaurant.name}
              </h1>

              <div style={{ display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap" }}>
                {/* Rating */}
                <div style={{ display: "flex", alignItems: "center", gap: 5 }}>
                  <span style={{ color: "#FFD93D", fontSize: "1rem" }}>★</span>
                  <span style={{
                    fontFamily: "'Space Mono',monospace", fontWeight: 700,
                    color: "#FFD93D", fontSize: "0.9rem",
                  }}>
                    {parseFloat(restaurant.rating) > 0 ? parseFloat(restaurant.rating).toFixed(1) : "–"}
                  </span>
                </div>

                {/* Item count */}
                <div style={{
                  background: `${palette.accent}25`, border: `1px solid ${palette.accent}50`,
                  borderRadius: 8, padding: "2px 10px",
                  fontFamily: "'Nunito',sans-serif", fontWeight: 700,
                  fontSize: "0.75rem", color: palette.accent,
                }}>
                  {totalItems} item{totalItems !== 1 ? "s" : ""}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ── Search bar ────────────────────────────────────────────────────
function SearchBar({ value, onChange, accent }) {
  const [focused, setFocused] = useState(false);
  return (
    <div style={{
      position: "relative",
      border: `1.5px solid ${focused ? accent : "rgba(255,255,255,0.1)"}`,
      borderRadius: 14, overflow: "hidden",
      background: focused ? `${accent}0c` : "rgba(255,255,255,0.04)",
      transition: "border-color 0.25s, background 0.25s, box-shadow 0.25s",
      boxShadow: focused ? `0 0 0 3px ${accent}20` : "none",
    }}>
      <div style={{
        position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)",
        color: focused ? accent : "rgba(255,255,255,0.25)",
        transition: "color 0.25s", pointerEvents: "none",
      }}>
        <svg width={16} height={16} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.3} strokeLinecap="round">
          <circle cx={11} cy={11} r={8} />
          <line x1={21} y1={21} x2={16.65} y2={16.65} />
        </svg>
      </div>
      <input
        value={value}
        onChange={e => onChange(e.target.value)}
        onFocus={() => setFocused(true)}
        onBlur={() => setFocused(false)}
        placeholder="Search items…"
        style={{
          width: "100%", background: "none", border: "none", outline: "none",
          padding: "12px 40px 12px 42px",
          fontFamily: "'Nunito', sans-serif", fontWeight: 600,
          fontSize: "0.92rem", color: "#fff", caretColor: accent,
        }}
      />
      {value && (
        <button onClick={() => onChange("")} style={{
          position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)",
          background: "rgba(255,255,255,0.08)", border: "none", borderRadius: "50%",
          width: 22, height: 22, cursor: "pointer", color: "rgba(255,255,255,0.5)",
          display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14,
        }}>×</button>
      )}
    </div>
  );
}

// ── Main Page ─────────────────────────────────────────────────────
export default function RestaurantItemsPage() {
  const { resId } = useParams();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();

  const cuisineParam = searchParams.get("cuisine") ?? "";
  const dishParam    = searchParams.get("dish")    ?? "";

  const [searchQuery, setSearchQuery] = useState("");
  const [mounted, setMounted] = useState(false);
  useEffect(() => { setTimeout(() => setMounted(true), 60); }, []);

  // Redux selectors
  const allBindings  = useSelector(selectEnrichedBindings);
  const restaurant   = useSelector(selectRestaurantById(resId));

  // Active palette
  const palette = getPalette(cuisineParam || dishParam);

  // Filter bindings: must match resId + keyword
  const filtered = useMemo(() => {
    return allBindings.filter(b => {
      if (!b.dishDetails || !b.restaurantDetails) return false;
      if (String(b.res_id) !== String(resId)) return false;
      const cuisineMatch = cuisineParam
        ? b.cuisine?.toLowerCase() === cuisineParam.toLowerCase()
        : true;
      const dishMatch = dishParam
        ? b.dish?.toLowerCase() === dishParam.toLowerCase()
        : true;
      return cuisineMatch && dishMatch;
    });
  }, [allBindings, resId, cuisineParam, dishParam]);

  // De-duplicate by dish_id (same dish can appear in multiple bindings)
  const uniqueDishes = useMemo(() => {
    const seen = new Set();
    return filtered
      .filter(b => {
        if (seen.has(b.dish_id)) return false;
        seen.add(b.dish_id);
        return true;
      })
      .map(b => ({
        ...b.dishDetails,
        cuisine: b.cuisine,
        dishKeyword: b.dish,
      }));
  }, [filtered]);

  // Search filter
  const displayDishes = useMemo(() => {
    if (!searchQuery.trim()) return uniqueDishes;
    const q = searchQuery.toLowerCase();
    return uniqueDishes.filter(d =>
      d.dish_name?.toLowerCase().includes(q) ||
      d.dishKeyword?.toLowerCase().includes(q) ||
      d.cuisine?.toLowerCase().includes(q)
    );
  }, [uniqueDishes, searchQuery]);

  // Active keyword label for header
  const keywordLabel = dishParam || cuisineParam;

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(160deg,#0a0814 0%,#110d24 50%,#080f1e 100%)",
      color: "#fff",
      fontFamily: "'Nunito', sans-serif",
      position: "relative",
      overflowX: "hidden",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800;900&family=Space+Mono:wght@700&display=swap');

        @keyframes dishIn {
          0%   { opacity:0; transform: translateY(28px) scale(0.93); }
          100% { opacity:1; transform: translateY(0) scale(1); }
        }
        @keyframes heroIn {
          0%   { opacity:0; transform: translateY(-12px); }
          100% { opacity:1; transform: translateY(0); }
        }
        @keyframes fadeUp {
          0%   { opacity:0; transform: translateY(16px); }
          100% { opacity:1; transform: translateY(0); }
        }
        @keyframes barIn {
          0%   { opacity:0; transform: translateY(10px); }
          100% { opacity:1; transform: translateY(0); }
        }
        ::placeholder { color: rgba(255,255,255,0.22) !important; }
        * { box-sizing: border-box; }
        ::-webkit-scrollbar { width: 5px; }
        ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 3px; }
      `}</style>

      {/* Ambient blobs */}
      <div style={{
        position: "fixed", top: -100, right: -100, width: 480, height: 480, borderRadius: "50%",
        background: `radial-gradient(circle, ${palette.accent}14 0%, transparent 70%)`,
        pointerEvents: "none", zIndex: 0,
      }} />
      <div style={{
        position: "fixed", bottom: -60, left: -60, width: 360, height: 360, borderRadius: "50%",
        background: `radial-gradient(circle, ${palette.accent}0c 0%, transparent 70%)`,
        pointerEvents: "none", zIndex: 0,
      }} />

      {/* ── Restaurant Hero ── */}
      <RestaurantHero
        restaurant={restaurant}
        palette={palette}
        totalItems={uniqueDishes.length}
      />

      {/* ── Sticky toolbar (search + back) ── */}
      <div style={{
        position: "sticky", top: 0, zIndex: 50,
        background: "rgba(10,8,20,0.88)", backdropFilter: "blur(20px)",
        borderBottom: `1px solid rgba(255,255,255,0.06)`,
        padding: "12px 20px",
        animation: "barIn 0.4s ease 0.2s both",
      }}>
        <div style={{ maxWidth: 900, margin: "0 auto", display: "flex", gap: 12, alignItems: "center" }}>
          <button
            onClick={() => navigate(-1)}
            style={{
              flexShrink: 0,
              background: "rgba(255,255,255,0.06)", border: "1px solid rgba(255,255,255,0.1)",
              borderRadius: 12, padding: "9px 14px", color: "rgba(255,255,255,0.7)",
              cursor: "pointer", fontFamily: "'Nunito',sans-serif", fontWeight: 700,
              fontSize: "0.82rem", display: "flex", alignItems: "center", gap: 5,
              transition: "all 0.2s",
            }}
            onMouseEnter={e => { e.currentTarget.style.background = "rgba(255,255,255,0.1)"; e.currentTarget.style.color = "#fff"; }}
            onMouseLeave={e => { e.currentTarget.style.background = "rgba(255,255,255,0.06)"; e.currentTarget.style.color = "rgba(255,255,255,0.7)"; }}
          >
            <svg width={14} height={14} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.5} strokeLinecap="round">
              <path d="M19 12H5M12 5l-7 7 7 7" />
            </svg>
            Back
          </button>

          <div style={{ flex: 1 }}>
            <SearchBar value={searchQuery} onChange={setSearchQuery} accent={palette.accent} />
          </div>

          {/* Result count pill */}
          <div style={{
            flexShrink: 0,
            background: `${palette.accent}1a`, border: `1px solid ${palette.accent}40`,
            borderRadius: 10, padding: "8px 14px",
            fontFamily: "'Space Mono',monospace", fontWeight: 700,
            fontSize: "0.78rem", color: palette.accent, whiteSpace: "nowrap",
          }}>
            {displayDishes.length} / {uniqueDishes.length}
          </div>
        </div>
      </div>

      {/* ── Content ── */}
      <div style={{
        maxWidth: 900, margin: "0 auto",
        padding: "28px 20px 80px",
        opacity: mounted ? 1 : 0, transition: "opacity 0.4s ease",
      }}>

        {/* Section header */}
        <div style={{
          display: "flex", alignItems: "center", gap: 12, marginBottom: 24,
          animation: "fadeUp 0.5s ease 0.1s both",
        }}>
          <span style={{ fontSize: "1.6rem" }}>{palette.emoji}</span>
          <div>
            <div style={{
              fontFamily: "'Nunito',sans-serif", fontWeight: 900,
              fontSize: "clamp(1rem, 2.5vw, 1.25rem)",
              background: `linear-gradient(${palette.grad})`,
              WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
              textTransform: "capitalize",
            }}>
              {keywordLabel || "Menu Items"}
            </div>
            {searchQuery && (
              <div style={{ color: "rgba(255,255,255,0.35)", fontSize: "0.75rem", marginTop: 2 }}>
                showing results for "{searchQuery}"
              </div>
            )}
          </div>

          {/* Decorative line */}
          <div style={{
            flex: 1, height: 1,
            background: `linear-gradient(90deg, ${palette.accent}50, transparent)`,
            marginLeft: 4,
          }} />
        </div>

        {/* Grid or empty state */}
        {displayDishes.length === 0 ? (
          <div style={{
            textAlign: "center", padding: "70px 24px",
            animation: "fadeUp 0.5s ease both",
          }}>
            <div style={{ fontSize: "3.5rem", marginBottom: 14 }}>
              {searchQuery ? "🔍" : "🍽️"}
            </div>
            <div style={{
              fontFamily: "'Nunito',sans-serif", fontWeight: 800,
              fontSize: "1.1rem", color: "rgba(255,255,255,0.5)", marginBottom: 8,
            }}>
              {searchQuery ? `No items matching "${searchQuery}"` : "No items found"}
            </div>
            <div style={{ color: "rgba(255,255,255,0.25)", fontSize: "0.82rem" }}>
              {searchQuery ? "Try a different search term" : "Data is loading — check back shortly"}
            </div>
            {searchQuery && (
              <button
                onClick={() => setSearchQuery("")}
                style={{
                  marginTop: 20,
                  background: `${palette.accent}1a`, border: `1px solid ${palette.accent}40`,
                  borderRadius: 12, padding: "10px 22px", cursor: "pointer",
                  color: palette.accent, fontFamily: "'Nunito',sans-serif",
                  fontWeight: 700, fontSize: "0.88rem",
                }}
              >
                Clear search
              </button>
            )}
          </div>
        ) : (
          <div style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))",
            gap: 22,
          }}>
            {displayDishes.map((dish, idx) => (
              <DishCard
                key={dish.dish_id}
                dish={dish}
                accent={palette.accent}
                glow={palette.glow}
                idx={idx}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
